type NodeComponentProps<T extends NodeNameType> =
  // Explicitly specify variants, args, and overrides as objects
  {
    variants?: PlasmicLoaction__VariantsArgs;
    args?: PlasmicLoaction__ArgsType;
    overrides?: NodeOverridesType<T>;
  } &
    // Specify variants directly as props
    Omit<PlasmicLoaction__VariantsArgs, ReservedPropsType> &
    // Specify args directly as props
    Omit<PlasmicLoaction__ArgsType, ReservedPropsType> &
    // Specify overrides for each element directly as props
    Omit<
      NodeOverridesType<T>,
      ReservedPropsType | VariantPropType | ArgPropType
    > &
    // Specify props for the root element
    Omit<
      Partial<React.ComponentProps<NodeDefaultElementType[T]>>,
      ReservedPropsType | VariantPropType | ArgPropType | DescendantsType<T>
    >;

function makeNodeComponent<NodeName extends NodeNameType>(nodeName: NodeName) {
  type PropsType = NodeComponentProps<NodeName> & { key?: React.Key };
  const func = function <T extends PropsType>(
    props: T & StrictProps<T, PropsType>
  ) {
    const { variants, args, overrides } = React.useMemo(
      () =>
        deriveRenderOpts(props, {
          name: nodeName,
          descendantNames: PlasmicDescendants[nodeName],
          internalArgPropNames: PlasmicLoaction__ArgProps,
          internalVariantPropNames: PlasmicLoaction__VariantProps
        }),
      [props, nodeName]
    );
    return PlasmicLoaction__RenderFunc({
      variants,
      args,
      overrides,
      forNode: nodeName
    });
  };
  if (nodeName === "root") {
    func.displayName = "PlasmicLoaction";
  } else {
    func.displayName = `PlasmicLoaction.${nodeName}`;
  }
  return func;
}

export const PlasmicLoaction = Object.assign(
  // Top-level PlasmicLoaction renders the root element
  makeNodeComponent("root"),
  {
    // Helper components rendering sub-elements
    embedHtml: makeNodeComponent("embedHtml"),
    apiRequest: makeNodeComponent("apiRequest"),
    state: makeNodeComponent("state"),
    city: makeNodeComponent("city"),
    loaction: makeNodeComponent("loaction"),
    call: makeNodeComponent("call"),

    // Metadata about props expected for PlasmicLoaction
    internalVariantProps: PlasmicLoaction__VariantProps,
    internalArgProps: PlasmicLoaction__ArgProps
  }
);

export default PlasmicLoaction;
/* prettier-ignore-end */
